INSERT INTO posts (slug, title, excerpt, content, cover_image, published_at) VALUES ('autoslalom-st-gallenkirch-ersatztermin-latschau', 'Autoslalom St. Gallenkirch — Ersatztermin Latschau', 'Am 3. Mai fand erstmals der Autoslalom in St. Gallenkirch statt. Der Rallyeclub Klostertal bedankt sich bei allen Funktionären, Zuschauern und natürlich auch bei den Fahrern. Wir …', 'Am 3. Mai fand erstmals der Autoslalom in St. Gallenkirch statt. Der Rallyeclub Klostertal bedankt sich bei allen Funktionären, Zuschauern und natürlich auch bei den Fahrern. Wir freuen uns auf weitere Veranstaltungen.', NULL, '2014-06-15');
